// Source manifest snapshot -- A3 Step 1.
// This is the ONLY point that ever lists the project directory tree.
// Every later step in this workflow, and every citation check in
// Quality Gate, reads from this frozen list -- never a live re-scan.

const fs = require('fs');
const path = require('path');

const prefix = $json.project_prefix;
if (!/^[A-Za-z0-9_-]{1,64}$/.test(prefix)) {
  throw new Error('Invalid project_prefix reached Decode -- should have been filtered at Trigger.');
}

const root = path.join('Working', prefix);

function walk(dir, base) {
  let out = [];
  const entries = fs.readdirSync(dir, { withFileTypes: true });
  for (const e of entries) {
    const full = path.join(dir, e.name);
    const rel = path.join(base, e.name);
    if (e.isDirectory()) {
      out = out.concat(walk(full, rel));
    } else {
      out.push({ relative_path: rel, absolute_path: path.resolve(full) });
    }
  }
  return out;
}

const allFiles = walk(root, '');

// Secondary guard: known operational filenames are never evidence,
// no matter where in the tree they appear.
const IGNORE_NAMES = new Set([
  'contacts.json', 'send_log.json', 'suppression.json', 'pipeline.json',
  'engagement_log.json', 'linkedin_queue.json', 'reminder_log.json',
  'ai_corrected_contacts.json'
]);

const manifest = allFiles.filter(f => !IGNORE_NAMES.has(path.basename(f.relative_path)));

// Frozen, written once. Nothing after this point re-lists the directory.
const manifestPath = path.join(root, 'manifest.json');
fs.writeFileSync(manifestPath, JSON.stringify({
  project_prefix: prefix,
  captured_at: new Date().toISOString(),
  files: manifest
}, null, 2), 'utf8');

return manifest.map(f => ({ json: { project_prefix: prefix, ...f } }));

// File filter (A3): only recognized types, size cap, case-normalized
// duplicate .docx/.pdf matching. Everything else is skipped and logged,
// never read. This node NEVER opens a file -- it only decides eligibility.

const path = require('path');
const fs = require('fs');

const ALLOWED_EXT = new Set(['.md', '.json', '.pdf', '.docx', '.xlsx']);
const MAX_BYTES = 25 * 1024 * 1024;

const items = $input.all();
const byLowerBase = new Map();

for (const item of items) {
  const ext = path.extname(item.json.relative_path).toLowerCase();
  const base = item.json.relative_path.slice(0, -ext.length);
  const lowerKey = path.join(path.dirname(item.json.relative_path), base).toLowerCase();
  if (!byLowerBase.has(lowerKey)) byLowerBase.set(lowerKey, []);
  byLowerBase.get(lowerKey).push({ item, ext });
}

const eligible = [];
const skipped = [];

for (const [, group] of byLowerBase) {
  // Duplicate .docx/.pdf pair sharing a base name -- .docx wins, logged not read.
  const docx = group.find(g => g.ext === '.docx');
  const pdf = group.find(g => g.ext === '.pdf');
  if (docx && pdf) {
    skipped.push({ path: pdf.item.json.relative_path, reason: 'duplicate_format_pdf_skipped_for_docx' });
  }

  for (const { item, ext } of group) {
    if (docx && pdf && ext === '.pdf') continue; // already logged as skipped above

    if (!ALLOWED_EXT.has(ext)) {
      skipped.push({ path: item.json.relative_path, reason: 'unrecognized_file_type' });
      continue;
    }

    let size = 0;
    try { size = fs.statSync(item.json.absolute_path).size; } catch (e) { /* fall through, flagged below */ }
    if (size > MAX_BYTES) {
      skipped.push({ path: item.json.relative_path, reason: 'exceeds_25mb_cap' });
      continue;
    }

    if (['.png', '.jpg', '.jpeg'].includes(ext)) {
      const flagged = /rfp|solicitation|requirement/i.test(item.json.relative_path);
      skipped.push({ path: item.json.relative_path, reason: flagged ? 'image_flagged_for_review' : 'image_not_processed' });
      continue;
    }

    eligible.push(item.json);
  }
}

// Log skipped/flagged files to the exception log without stopping the batch.
const logPath = require('path').join('Working', items[0]?.json.project_prefix || '', 'decode_exceptions.json');
try { fs.writeFileSync(logPath, JSON.stringify(skipped, null, 2), 'utf8'); } catch (e) {}

return eligible.map(f => ({ json: f }));

// Per-file isolation with strict sequential processing (A3).
// Opens exactly one file, extracts text, explicitly dereferences the
// buffer before returning. Any parse exception is caught here and
// logged -- it never stops the batch.

const fs = require('fs');
const path = require('path');
const pdfParse = require('pdf-parse');
const mammoth = require('mammoth');
const ExcelJS = require('exceljs');

const file = $json;
const ext = path.extname(file.relative_path).toLowerCase();
// Case-folding is comparison-only elsewhere -- this uses the real,
// case-preserved absolute_path directly for the actual file read.
const absPath = file.absolute_path;

let result = { ...file, extraction_status: 'ok', text: '', pages: null };

try {
  if (ext === '.md') {
    let buf = fs.readFileSync(absPath, 'utf8');
    result.text = buf;
    buf = null; // explicit dereference before next file loads
  } else if (ext === '.docx') {
    let buf = fs.readFileSync(absPath);
    const extracted = await mammoth.extractRawText({ buffer: buf });
    result.text = extracted.value;
    buf = null;
  } else if (ext === '.pdf') {
    let buf = fs.readFileSync(absPath);
    const parsed = await pdfParse(buf);
    buf = null;

    // Per-page scanned-document guard (B5): ANY single page under 100
    // characters fails this file closed, not a whole-document average.
    const pageTexts = parsed.text.split('\f'); // form-feed page breaks from pdf-parse
    const thinPages = pageTexts.filter(p => p.trim().length < 100);
    if (thinPages.length > 0) {
      result.extraction_status = 'failed_closed_scanned_document';
      result.text = '';
      result.pages = pageTexts.length;
    } else {
      result.text = parsed.text;
      result.pages = pageTexts.length;
    }
  } else if (ext === '.xlsx') {
    const wb = new ExcelJS.Workbook();
    await wb.xlsx.readFile(absPath);
    const sheetsText = [];
    wb.eachSheet(sheet => {
      sheet.eachRow(row => {
        sheetsText.push(row.values.filter(v => v != null).join(' | '));
      });
    });
    result.text = sheetsText.join('\n');
  } else if (ext === '.json') {
    result.text = fs.readFileSync(absPath, 'utf8');
  }
} catch (e) {
  result.extraction_status = 'parse_exception';
  result.error = String(e.message || e);
  result.text = '';
}

return [{ json: result }];

// Chunked decode (context law, A3): structural-boundary splits, never
// raw character counts, minimum 25% overlap of the context budget.
// This applies only to text that actually needs chunking -- short files
// (like contacts.xlsx text or a short .md) pass through as one chunk.

const file = $json;
if (file.extraction_status !== 'ok' || !file.text) {
  return [{ json: { ...file, chunks: [] } }];
}

const CONTEXT_BUDGET_CHARS = 2048 * 3; // rough char-per-token budget headroom under OLLAMA_NUM_CTX
const CHUNK_SIZE = Math.floor(CONTEXT_BUDGET_CHARS * 0.6); // leaves room for instruction + output
const OVERLAP = Math.floor(CHUNK_SIZE * 0.25); // 25% overlap, minimum, per A3

// Split on structural boundaries -- paragraph breaks first, falling back
// to sentence ends -- never a blind character-count cut mid-word/mid-clause.
const paragraphs = file.text.split(/\n\s*\n/);

const chunks = [];
let current = '';
for (const para of paragraphs) {
  if ((current + '\n\n' + para).length > CHUNK_SIZE && current.length > 0) {
    chunks.push(current);
    // Start next chunk with the overlap tail of the previous one.
    current = current.slice(-OVERLAP) + '\n\n' + para;
  } else {
    current = current ? current + '\n\n' + para : para;
  }
}
if (current) chunks.push(current);

return chunks.map((text, idx) => ({
  json: {
    project_prefix: file.project_prefix,
    relative_path: file.relative_path,
    chunk_index: idx,
    chunk_text: text
  }
}));

// Deterministic merge (A3): combines per-chunk extractions into one
// structured JSON. Every fact carries a citation -- source file +
// location. A fact with no citation does not enter the Project Document.

const items = $input.all();
const byPath = {};

for (const item of items) {
  const raw = item.json;
  let facts = [];
  try {
    const parsed = JSON.parse(raw.response || '[]');
    facts = Array.isArray(parsed) ? parsed : [];
  } catch (e) {
    continue; // malformed model output for this chunk -- skip, don't crash the merge
  }

  const key = raw.relative_path || 'unknown';
  if (!byPath[key]) byPath[key] = [];

  for (const f of facts) {
    if (!f.fact || !f.location_hint) continue; // no citation, no entry -- non-negotiable
    byPath[key].push({
      fact: f.fact,
      citation: { file: key, location: f.location_hint }
    });
  }
}

return [{ json: { decoded_facts: byPath } }];

// Funding figure extraction (A3): one clean total for the ROI Full
// tier. If none extracts cleanly, this is logged unresolved -- the
// Tier Map workflow (03) reads this flag and floors the price + queues
// Manual Lever 1. This node never guesses a number.

const decoded = $json.decoded_facts;
const allFacts = Object.values(decoded).flat();

const moneyPattern = /\$[\d,]+(?:\.\d{2})?/g;
const candidates = [];
for (const f of allFacts) {
  const matches = f.fact.match(moneyPattern);
  if (matches) {
    for (const m of matches) {
      if (/total|grant|funding|award|not.to.exceed|nte/i.test(f.fact)) {
        candidates.push({ value: m, citation: f.citation, context: f.fact });
      }
    }
  }
}

const resolved = candidates.length === 1;

return [{
  json: {
    funding_figure_resolved: resolved,
    funding_figure: resolved ? candidates[0] : null,
    funding_figure_candidates: candidates
  }
}];

// Contact file emission (A3): locates the contact database anywhere
// in the frozen manifest -- typically .xlsx inside the intel subfolder
// -- and emits the canonical, project-isolated contacts.json.

const fs = require('fs');
const path = require('path');
const ExcelJS = require('exceljs');

const manifestRaw = fs.readFileSync(path.join('Working', $json.project_prefix, 'manifest.json'), 'utf8');
const manifest = JSON.parse(manifestRaw);

const contactFile = manifest.files.find(f => /\.xlsx$/i.test(f.relative_path) && /contact|database/i.test(f.relative_path));
if (!contactFile) {
  return [{ json: { contacts_found: false } }];
}

const wb = new ExcelJS.Workbook();
await wb.xlsx.readFile(contactFile.absolute_path);
const sheet = wb.worksheets[0];

const headerRow = sheet.getRow(1).values.map(v => String(v || '').trim().toLowerCase());
const nameIdx = headerRow.indexOf('name');
const orgIdx = headerRow.indexOf('organization');
const emailIdx = headerRow.indexOf('email');

const contacts = [];
sheet.eachRow((row, rowNum) => {
  if (rowNum === 1) return;
  const email = String(row.values[emailIdx] || '').trim();
  if (!email) return;
  // Format validation at emission -- malformed addresses never become
  // live contacts; they're logged for manual correction instead.
  const validFormat = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) && (email.match(/@/g) || []).length === 1;
  contacts.push({
    name: row.values[nameIdx] || '',
    organization: row.values[orgIdx] || '',
    email,
    valid_format: validFormat
  });
});

const outPath = path.join('Working', $json.project_prefix, 'contacts.json');
fs.writeFileSync(outPath, JSON.stringify(contacts, null, 2), 'utf8');

return [{ json: { contacts_found: true, total: contacts.length, malformed: contacts.filter(c => !c.valid_format).length } }];

// Deadline Law check (A8), performed here as part of Decode's output
// before Project Document creation, so Tier Map resolution (03) has
// the flag immediately available.

const decoded = $json.decoded_facts || {};
const allFacts = Object.values(decoded).flat();
const dateFact = allFacts.find(f => /due date|proposal due|submission deadline/i.test(f.fact));

let dueDate = null;
if (dateFact) {
  const m = dateFact.fact.match(/\b(\d{4}-\d{2}-\d{2}|\w+ \d{1,2},? \d{4})\b/);
  if (m) dueDate = new Date(m[1]);
}

const expired = dueDate ? dueDate.getTime() < Date.now() : null;

return [{ json: { due_date_raw: dateFact ? dateFact.fact : null, due_date_parsed: dueDate ? dueDate.toISOString() : null, expired_at_intake: expired } }];

// Create the Project Document -- consolidates decoded facts, funding
// figure, contact emission result, and deadline status into one file
// that Tier Map resolution and Build both read from.

const fs = require('fs');
const path = require('path');

const prefix = $('Source Manifest Snapshot').first().json.project_prefix;

const doc = {
  project_prefix: prefix,
  created_at: new Date().toISOString(),
  decoded_facts: $('Merge Chunks + Attach Citations').first().json.decoded_facts,
  funding: $('Extract Funding Figure').first().json,
  contacts: $('Emit contacts.json').first().json,
  deadline: $('Deadline Law Check').first().json
};

fs.writeFileSync(path.join('Working', prefix, 'project_document.json'), JSON.stringify(doc, null, 2), 'utf8');

return [{ json: { project_prefix: prefix, decode_complete: true } }];
